INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aviation-1dfb84e5-moex-00066', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'single_choice', '「世界聽障者的人數到2025年將達到9億人，其中因老化引發的傳音性聽障可透過 助聽器改善，但這些老人使用助聽器比率不高，主因為羞於戴助聽器、周圍聲音也 被擴大，以及操作不易等。他們若不用助聽器，與人溝通時則需要提高聲量，猶如 吵架氛圍，容易引發心理不適，減低交流意願。經研究1000Hz以上的周波數帶， 是言語明瞭度的關鍵，但是此周波數帶的聽力隨著老化而下降，可聽到聲音，但不 清晰。日人中石真一路開發『助聽喇叭』，以蜂巢板的喇叭增強高音域，並使音箱細 長化，鳴音部向後垂，便可『調強』1700Hz周波數，讓人聲清晰化，即可幫助輕度 聽障者。有別於傳統助聽器只是『擴大』所有聲音，助聽喇叭改善助聽器之不清晰、 不舒適的問題。過去的社會是聽障者配合健聽者戴『助聽器』；在合乎人性之『無障 礙環境規畫』時代，健聽者以『助聽喇叭』主動接近聽障者，成就無障礙之傾聽交 流環境，是文明社會的指標之一。」 有關因老化引發傳音性聽障的敘述，下列選項何者最符合文意？', '["改善的最好方式是配戴助聽器", "未積極改善容易產生心理相關問題", "形成的主因是無法辨別1700Hz周波數的子音", "老化的大腦無法將聲音轉化成可辨識的語言"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00067', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-13504c0c', 'sub-aviation-1dfb84e5-05', NULL, 'single_choice', '承上題，關於助聽喇叭的研發與使用，下列選項何者最不符合本文意旨？', '["助聽器的設計著重於處理音質問題，而助聽喇叭則著重於改善音量問題", "健聽者以「助聽喇叭」主動接近聽障者，可成就無障礙之傾聽交流環境", "公私部門的服務窗口，宜增設助聽喇叭，有助形塑無形的「無障礙空間」", "「助聽喇叭」的設計理念更合乎聽障者需求，可說是文明社會的指標之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
