  ('aviation-1dfb84e5-moex-00074', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '依司法院大法官解釋，有關宗教自由，下列敘述何者正確？', '["寺廟內部之組織結構、是否加入其他宗教性人民團體成為團體會員，不屬於宗教結社自由之保障範圍", "國家得基於人民之特定信仰予以優待", "強制有反戰信仰之信徒仍須服兵役，違反宗教自由", "內在信仰之自由，涉及思想、言論、信念及精神之層次，應受絕對之保障"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
  ('aviation-1dfb84e5-moex-00075', 'aviation-1dfb84e5', 'aviation-1dfb84e5-moex-112-7bf35b0f', 'sub-aviation-1dfb84e5-06', NULL, 'single_choice', '依憲法訴訟法規定，法官於審理案件時，認為應適用之法律牴觸憲法，應如何處理？', '["逕行拒絕適用", "停止審判，以法院名義向憲法法庭聲請判決", "停止審判，由所屬法院院長向憲法法庭聲請判決", "停止審判，層轉最高法院或最高行政法院向憲法法庭聲請判決"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "403", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL)
